SELECT MAX(efficiency_value) AS highest_efficiency
FROM fuel_efficiency
WHERE update_date >= '2023-01-01';

SELECT v.name, v.year, v.kilometer_per_liter
FROM vehicles v
JOIN vehicle_images vi ON v.vehicle_id = vi.vehicle_id;

SELECT COUNT(*) AS turbocharged_vehicles_count
FROM engine_specs
WHERE turbocharged = 1;
